document.addEventListener('DOMContentLoaded', () => {
    // 0. Hero Auto-Slider
    const heroSlides = document.querySelectorAll('.hero-slide');
    if (heroSlides.length > 0) {
        let currentSlide = 0;
        setInterval(() => {
            heroSlides[currentSlide].classList.remove('active');
            currentSlide = (currentSlide + 1) % heroSlides.length;
            heroSlides[currentSlide].classList.add('active');
        }, 5000); // Cross-fade every 5 seconds
    }

    // 1. Mobile Menu Toggle
    const mobileMenu = document.getElementById('mobile-menu');
    const navMenu = document.getElementById('nav-menu');
    
    if (mobileMenu && navMenu) {
        mobileMenu.addEventListener('click', () => {
            mobileMenu.classList.toggle('is-active');
            navMenu.classList.toggle('active');
        });

        // Close menu when clicking a link
        const navLinksMobile = navMenu.querySelectorAll('a');
        navLinksMobile.forEach(link => {
            link.addEventListener('click', () => {
                mobileMenu.classList.remove('is-active');
                navMenu.classList.remove('active');
            });
        });
    }

    // 2. Sticky Header with Scroll Effect
    const header = document.getElementById('main-header');
    
    window.addEventListener('scroll', () => {
        if (window.scrollY > 50) {
            header.style.boxShadow = '0 4px 6px -1px rgba(0, 0, 0, 0.1)';
            header.style.padding = '0';
        } else {
            header.style.boxShadow = 'none';
            header.style.padding = '0.5rem 0';
        }
    });

    // 2. Active Navigation Link Highlighting
    const sections = document.querySelectorAll('section');
    const navLinks = document.querySelectorAll('.desktop-menu a');

    window.addEventListener('scroll', () => {
        let current = '';
        sections.forEach(section => {
            const sectionTop = section.offsetTop;
            const sectionHeight = section.clientHeight;
            if (scrollY >= (sectionTop - 200)) {
                current = section.getAttribute('id');
            }
        });

        navLinks.forEach(link => {
            link.classList.remove('active');
            if (link.getAttribute('href').includes(current)) {
                link.classList.add('active');
            }
        });
    });

    // 3. Product Filtering
    const filterBtns = document.querySelectorAll('.filter-btn');
    const productCards = document.querySelectorAll('.product-card');

    filterBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            // Remove active class from all buttons
            filterBtns.forEach(b => b.classList.remove('active'));
            // Add active class to clicked button
            btn.classList.add('active');

            const filterValue = btn.getAttribute('data-filter');

            productCards.forEach(card => {
                if (filterValue === 'all' || card.getAttribute('data-category') === filterValue) {
                    card.classList.remove('hidden-card');
                } else {
                    card.classList.add('hidden-card');
                }
            });
        });
    });

    // 4. Smooth Scrolling for Anchor Links
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function (e) {
            e.preventDefault();
            const targetId = this.getAttribute('href');
            if(targetId === '#') return;
            
            const targetElement = document.querySelector(targetId);
            if(targetElement) {
                // Offset for fixed header
                const headerOffset = 80;
                const elementPosition = targetElement.getBoundingClientRect().top;
                const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

                window.scrollTo({
                    top: offsetPosition,
                    behavior: 'smooth'
                });
            }
        });
    });

    // 5. Form Submission Handling
    const consultationForm = document.getElementById('consultation-form');
    const successMessage = document.getElementById('form-success-message');

    if (consultationForm && successMessage) {
        consultationForm.addEventListener('submit', (e) => {
            e.preventDefault(); // Prevent page reload
            
            const nameInput = document.getElementById('name');
            const phoneInput = document.getElementById('phone');
            const serviceInput = document.getElementById('service');
            
            // Basic validation
            if (nameInput.value.trim() !== '' && phoneInput.value.trim() !== '') {
                // Generate WhatsApp URL
                const phoneNumber = "919876543210"; // Replace with clinic's actual WhatsApp number later
                let serviceText = serviceInput ? serviceInput.options[serviceInput.selectedIndex].text : "Consultation";
                const message = `Hello Sneha Clinic,\nI would like to book an appointment.\n\nName: ${nameInput.value.trim()}\nPhone: ${phoneInput.value.trim()}\nService: ${serviceText}`;
                
                const whatsappUrl = `https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`;
                
                // Open WhatsApp in new tab
                window.open(whatsappUrl, '_blank');
                
                // Hide form, show success message
                consultationForm.style.display = 'none';
                
                // Update success message text
                successMessage.innerHTML = `
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="48" height="48" style="color: var(--primary-teal); margin-bottom: 1rem;"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><polyline points="22 4 12 14.01 9 11.01"></polyline></svg>
                    <h3>Connecting to WhatsApp...</h3>
                    <p>We're opening WhatsApp to complete your booking. If it didn't open automatically, <a href="${whatsappUrl}" target="_blank" style="color: var(--primary-teal); text-decoration: underline;">click here</a>.</p>
                `;
                successMessage.style.display = 'block';
                
                // Scroll specifically to the success message
                successMessage.scrollIntoView({ behavior: 'smooth', block: 'center' });
            }
        });
    }

    // 6. Product Modal Handling
    const productData = {
        signia: {
            title: "Signia Pure Charge&Go",
            desc: "The Signia Pure Charge&Go features award-winning design seamlessly combined with incredible sound quality. Powered by the latest AI tech for superior noise cancellation.",
            features: [
                "Invisible comfort",
                "AI-powered noise cancellation",
                "Portable wireless charging",
                "Bluetooth streaming for calls and music"
            ]
        },
        phonak: {
            title: "Phonak Audéo Lumity",
            desc: "Phonak Audéo Lumity focuses on giving you improved speech understanding with its unique Phonak SmartSpeech™ Technology. Enjoy conversations in any environment.",
            features: [
                "Unmatched speech clarity",
                "Universal connectivity (iOS & Android)",
                "Adaptive hearing in busy environments",
                "Water-resistant design"
            ]
        },
        widex: {
            title: "Widex Moment Sheer",
            desc: "With Widex Moment Sheer, we've elevated the standard in pure, natural sound. Zero delay means you hear the moment exactly as it happens.",
            features: [
                "Most natural sound (ZeroDelay™ logic)",
                "Ultra-fast sound processing",
                "Long-lasting battery",
                "Advanced AI customization via App"
            ]
        }
    };

    const modal = document.getElementById('product-modal');
    const modalBody = document.getElementById('modal-body-content');
    const modalCloseBtn = document.getElementById('modal-close-btn');
    const pCards = document.querySelectorAll('.product-card');

    if (modal && pCards.length > 0) {
        
        // Close modal functions
        const closeModal = () => {
            modal.classList.remove('active');
            document.body.style.overflow = '';
        };
        
        // Open modal
        pCards.forEach(card => {
            const btn = card.querySelector('.view-details-btn');
            
            const openModal = () => {
                const productId = btn ? btn.getAttribute('data-product-id') : '';
                const data = productData[productId];
                
                if (data) {
                    modalBody.innerHTML = `
                        <h3>${data.title}</h3>
                        <p>${data.desc}</p>
                        <ul>
                            ${data.features.map(f => `<li>${f}</li>`).join('')}
                        </ul>
                        <button class="btn btn-primary" id="modal-book-btn">Book Consultation</button>
                    `;
                    modal.classList.add('active');
                    document.body.style.overflow = 'hidden'; // Prevent scrolling
                    
                    // Add listener to the dynamic button
                    const bookBtn = document.getElementById('modal-book-btn');
                    if(bookBtn) {
                        bookBtn.addEventListener('click', () => {
                            closeModal();
                            const targetElement = document.getElementById('booking');
                            if(targetElement) {
                                const headerOffset = 80;
                                const elementPosition = targetElement.getBoundingClientRect().top;
                                const offsetPosition = elementPosition + window.pageYOffset - headerOffset;
                                window.scrollTo({
                                    top: offsetPosition,
                                    behavior: 'smooth'
                                });
                            }
                        });
                    }
                }
            };

            card.addEventListener('click', openModal);
            if (btn) {
                btn.addEventListener('click', (e) => {
                    e.stopPropagation();
                    openModal();
                });
            }
        });

        modalCloseBtn.addEventListener('click', closeModal);
        
        // Close on overlay click
        modal.querySelector('.modal-overlay').addEventListener('click', closeModal);
        
        // Close on Escape key
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && modal.classList.contains('active')) {
                closeModal();
            }
        });
    }

    // 7. Interactive Ambient Waves Parallax
    const wave1 = document.querySelector('.wave-1');
    const wave2 = document.querySelector('.wave-2');
    const wave3 = document.querySelector('.wave-3');

    if (wave1 || wave2 || wave3) {
        window.addEventListener('scroll', () => {
            // Use requestAnimationFrame for smooth performance
            window.requestAnimationFrame(() => {
                const scrollY = window.scrollY;
                if(wave1) wave1.style.transform = `translateY(${scrollY * 0.15}px)`;
                if(wave2) wave2.style.transform = `translateY(${scrollY * -0.08}px)`;
                if(wave3) wave3.style.transform = `translateY(${scrollY * 0.05}px)`;
            });
        });
    }

    // 8. Interactive Hearing Loss Simulator
    const simPlayBtn = document.getElementById('sim-play-btn');
    const simLevels = document.querySelectorAll('.sim-level');
    const simVisualizer = document.getElementById('sim-visualizer');
    const simBars = document.querySelectorAll('.sim-bar');
    const simStatusText = document.getElementById('sim-status-text');

    if (simPlayBtn) {
        let audioContext;
        let audioElement;
        let track;
        let biquadFilter;
        let analyser;
        let isPlaying = false;
        let animationId;

        const initAudio = () => {
            if (audioContext) return; // Already initialized

            const AudioContext = window.AudioContext || window.webkitAudioContext;
            audioContext = new AudioContext();
            
            // Using a realistic spoken conversation for simulation
            audioElement = new Audio('data:audio/mp4;base64,');
            // Removed crossOrigin to avoid local CORS block
            audioElement.loop = true;

            track = audioContext.createMediaElementSource(audioElement);
            biquadFilter = audioContext.createBiquadFilter();
            analyser = audioContext.createAnalyser();

            // Setup default filter (essentially bypassed)
            biquadFilter.type = "lowpass";
            biquadFilter.frequency.value = 20000;

            analyser.fftSize = 64;

            track.connect(biquadFilter);
            biquadFilter.connect(analyser);
            analyser.connect(audioContext.destination);

            audioElement.addEventListener('ended', () => {
                isPlaying = false;
                updatePlayButton();
                cancelAnimationFrame(animationId);
            });
        };

        const updateFilters = (level) => {
            if (!biquadFilter) return;

            // Hearing Loss Simulation via Lowpass
            switch(level) {
                case 'normal':
                    biquadFilter.frequency.setTargetAtTime(20000, audioContext.currentTime, 0.5);
                    simStatusText.textContent = "Normal Hearing: crisp highs and clear speech frequencies.";
                    break;
                case 'mild':
                    biquadFilter.frequency.setTargetAtTime(1500, audioContext.currentTime, 0.5);
                    simStatusText.textContent = "Mild Loss: high-frequency consonant sounds become muffled.";
                    break;
                case 'severe':
                    biquadFilter.frequency.setTargetAtTime(400, audioContext.currentTime, 0.5);
                    simStatusText.textContent = "Severe Loss: completely muffled and difficult to understand conversation.";
                    break;
            }
        };

        const drawVisualizer = () => {
            if (!isPlaying) return;
            animationId = requestAnimationFrame(drawVisualizer);
            
            const bufferLength = analyser.frequencyBinCount;
            const dataArray = new Uint8Array(bufferLength);
            analyser.getByteFrequencyData(dataArray);

            const step = Math.floor(bufferLength / simBars.length) || 1;
            
            simBars.forEach((bar, index) => {
                const dataIndex = index * step;
                // scale value appropriately
                const height = Math.max(10, (dataArray[dataIndex] / 255) * 80);
                bar.style.height = `${height}px`;
            });
        };

        const updatePlayButton = () => {
            if (isPlaying) {
                simPlayBtn.innerHTML = `<svg viewBox="0 0 24 24" width="24" height="24" fill="currentColor"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/></svg> <span>Pause Simulation</span>`;
                simVisualizer.classList.add('playing');
            } else {
                simPlayBtn.innerHTML = `<svg viewBox="0 0 24 24" width="24" height="24" fill="currentColor"><path d="M8 5v14l11-7z"/></svg> <span>Listen to Simulation</span>`;
                simVisualizer.classList.remove('playing');
                simBars.forEach(bar => bar.style.height = '10px');
            }
        };

        simPlayBtn.addEventListener('click', () => {
            initAudio();

            if (audioContext.state === 'suspended') {
                audioContext.resume();
            }

            if (isPlaying) {
                audioElement.pause();
                isPlaying = false;
                cancelAnimationFrame(animationId);
            } else {
                audioElement.play();
                isPlaying = true;
                drawVisualizer();
            }
            updatePlayButton();
        });

        simLevels.forEach(btn => {
            btn.addEventListener('click', () => {
                simLevels.forEach(b => b.classList.remove('active'));
                btn.classList.add('active');
                
                initAudio();
                const filterType = btn.getAttribute('data-filter');
                updateFilters(filterType);
            });
        });
    }

    // 9. FAQ Accordion
    const faqItems = document.querySelectorAll('.faq-item');
    if (faqItems.length > 0) {
        faqItems.forEach(item => {
            const questionBtn = item.querySelector('.faq-question');
            questionBtn.addEventListener('click', () => {
                // Close other open items
                faqItems.forEach(otherItem => {
                    if (otherItem !== item && otherItem.classList.contains('active')) {
                        otherItem.classList.remove('active');
                    }
                });
                // Toggle current item
                item.classList.toggle('active');
            });
        });
    }

    // 10. Digital Screener Quiz Logic
    const startQuizBtn = document.getElementById('start-quiz-btn');
    const quizIntro = document.getElementById('quiz-intro');
    const quizQs = document.getElementById('quiz-questions');
    const quizResults = document.getElementById('quiz-results');
    const questionText = document.getElementById('question-text');
    const quizOptions = document.querySelectorAll('.quiz-option');
    const progressBar = document.getElementById('quiz-progress-bar');
    const stepText = document.getElementById('quiz-step-text');
    const retakeQuizBtn = document.getElementById('retake-quiz-btn');
    const bookResultBtn = document.getElementById('book-result-btn');
    const resultHeadline = document.getElementById('result-headline');
    const resultDesc = document.getElementById('result-description');

    const questions = [
        "Do people seem to mumble or speak softer than they used to?",
        "Do you have difficulty following a conversation when there is background noise, like in a restaurant?",
        "Do you often avoid social gatherings or family dinners because you find it exhausting to listen?",
        "Do others complain that you play the TV or radio too loudly?",
        "Do you find it difficult to pinpoint which direction a sound is coming from?",
        "Do you struggle to hear clearly on phone calls without seeing the person's face?",
        "Do you frequently have to ask people to repeat themselves?",
        "Do you experience persistent ringing, roaring, or buzzing sounds in your ears?"
    ];

    let currentQ = 0;
    let totalScore = 0;
    let hasTinnitus = false;

    if (startQuizBtn) {
        startQuizBtn.addEventListener('click', () => {
            quizIntro.style.display = 'none';
            quizQs.style.display = 'block';
            currentQ = 0;
            totalScore = 0;
            hasTinnitus = false;
            updateQuestion();
        });

        quizOptions.forEach(btn => {
            btn.addEventListener('click', (e) => {
                const score = parseInt(e.target.getAttribute('data-value'));
                totalScore += score;
                
                // Question index 7 is the Tinnitus question
                if (currentQ === 7 && score > 0) {
                    hasTinnitus = true;
                }
                
                currentQ++;
                
                if (currentQ < questions.length) {
                    updateQuestion();
                } else {
                    showResults();
                }
            });
        });

        retakeQuizBtn.addEventListener('click', () => {
            quizResults.style.display = 'none';
            quizIntro.style.display = 'block';
        });

        bookResultBtn.addEventListener('click', () => {
            document.getElementById('booking').scrollIntoView({ behavior: 'smooth' });
        });
    }

    function updateQuestion() {
        questionText.style.opacity = '0';
        setTimeout(() => {
            questionText.textContent = questions[currentQ];
            stepText.textContent = `Question ${currentQ + 1} of ${questions.length}`;
            progressBar.style.width = `${((currentQ + 1) / questions.length) * 100}%`;
            questionText.style.opacity = '1';
        }, 200);
    }

    function showResults() {
        quizQs.style.display = 'none';
        quizResults.style.display = 'block';
        
        if (hasTinnitus) {
            resultHeadline.textContent = "Tinnitus Evaluation & Management";
            resultDesc.textContent = "You indicated experiencing persistent ringing or buzzing in your ears. We highly recommend a specialized Tinnitus evaluation to identify the root cause and explore effective relief strategies.";
        } else if (totalScore >= 18) {
            resultHeadline.textContent = "Comprehensive Audiological Assessment";
            resultDesc.textContent = "Your answers indicate significant difficulty in hearing clearly across multiple environments. A thorough diagnostic test will help us pinpoint the exact nature of your hearing profile and explore advanced medical solutions.";
        } else if (totalScore >= 8) {
            resultHeadline.textContent = "Hearing Aid Consultation";
            resultDesc.textContent = "You are experiencing some frustrating moments in noisy environments or social settings. A consultation will help determine if specialized tuning or a modern discreet device can restore your clarity.";
        } else {
            resultHeadline.textContent = "Routine Hearing Health Check";
            resultDesc.textContent = "Your hearing seems generally solid! We recommend a routine check-up to ensure your ear health and current devices remain in optimal condition.";
        }
    }
});
